select *
from knowledge_chunk
where deleted = 0

    and knowledge_base_id = #{query.knowledgeBaseId}


    and directory_id = #{query.directoryId}


    and document_uid = #{query.documentId}


    and document_version_uid = #{query.versionId}


    and publish_status = #{query.publishStatus}


    and enabled = #{query.enabled}

order by document_id desc, chunk_no asc

select *
from knowledge_chunk
where deleted = 0
  and knowledge_base_id = #{query.knowledgeBaseId}

    and directory_id = #{query.directoryId}


    and document_uid = #{query.documentId}


    and publish_status = 'PUBLISHED'
    and enabled = 1

order by update_time desc
limit #{query.limitSize}

mapper.update:
update knowledge_chunk
set deleted = 1,
    enabled = 0
where document_id = #{documentId}
  and document_version_id = #{versionId}
  and deleted = 0

update knowledge_chunk
set publish_status = #{publishStatus},
    enabled = #{enabled}
where document_id = #{documentId}
  and document_version_id = #{versionId}
  and deleted = 0
